INSERT INTO `block_revisions` (`id`, `block_id`, `page_id`, `version`, `block_type`, `sort_order`, `data`, `status`, `revised_by`, `created_at`) VALUES ('59', '6', '3', '4', 'gallery', '1', '{\"title\":\"Photo Gallery\",\"columns\":3,\"images\":[{\"url\":\"\\/gallery\\/school_image.jpg\",\"title\":\"School Campus Front View\",\"description\":\"Our spacious CBSE affiliated main campus building showing architectural grandeur.\"},{\"url\":\"\\/gallery\\/S1.jpg\",\"title\":\"School Building View\",\"description\":\"Vibrant academic blocks designed for learning comfort and student safety.\"},{\"url\":\"\\/gallery\\/S2.jpg\",\"title\":\"Interactive Learning Sessions\",\"description\":\"Students engaged in high-tech, collaborative classroom learning methodologies.\"},{\"url\":\"\\/gallery\\/S3.jpg\",\"title\":\"Outdoor Play Fields\",\"description\":\"Extensive sports facilities supporting physical mastery and athletic teamwork.\"},{\"url\":\"\\/gallery\\/S4.jpg\",\"title\":\"Annual Day Celebrations\",\"description\":\"Students presenting diverse cultural themes on the school stage.\"},{\"url\":\"\\/gallery\\/475852311_1078258867659773_1745477012267400081_n.jpg\",\"title\":\"Cultural Dance Performance\",\"description\":\"A colorful representation of traditional dance forms during the annual functions.\"},{\"url\":\"\\/gallery\\/476138870_1078258874326439_5129546497190358996_n.jpg\",\"title\":\"Theme-Based Stage Performance\",\"description\":\"Student choir presenting theatrical compositions for guests and parents.\"},{\"url\":\"\\/gallery\\/476158807_1078258894326437_7145252019572213562_n.jpg\",\"title\":\"Felicitation Ceremony\",\"description\":\"Honoring academic toppers and gold medalists with prestigious school awards.\"},{\"url\":\"\\/gallery\\/476235910_1078258944326432_8241233402632905083_n.jpg\",\"title\":\"Inter-House Drama Competition\",\"description\":\"Creative and drama presentations demonstrating theatrical talents of students.\"},{\"url\":\"\\/gallery\\/480946908_9424619570931799_6224709536946211302_n.jpg\",\"title\":\"Practical Laboratory Experiments\",\"description\":\"Science students observing chemical transformations under faculty supervision.\"},{\"url\":\"\\/gallery\\/484293291_9543954775664944_7864623137556454078_n.jpg\",\"title\":\"Computer Resource Center\",\"description\":\"Students executing python coding assignments in the technology lab.\"},{\"url\":\"\\/gallery\\/484834180_9543954788998276_1596571234836515262_n.jpg\",\"title\":\"Library Study Session\",\"description\":\"Developing reference skills and reading routines in the silent reading zone.\"},{\"url\":\"\\/gallery\\/484869461_9543954642331624_7824644525015015823_n.jpg\",\"title\":\"Scientific Research Project\",\"description\":\"Senior school batch presenting physics scale models in the exhibition.\"},{\"url\":\"\\/gallery\\/485015441_1112500694235590_465583318981687471_n.jpg\",\"title\":\"Inter-School Cricket Match\",\"description\":\"Greenwood cricket squad demonstrating stellar performance in the finals.\"},{\"url\":\"\\/gallery\\/485031812_1112500564235603_7469861559809913422_n.jpg\",\"title\":\"Athletic Track Events\",\"description\":\"Junior students competing in sprinting heats on the synthetic track.\"},{\"url\":\"\\/gallery\\/485060902_1112500574235602_6330663818326931872_n.jpg\",\"title\":\"Football Championship Trophy\",\"description\":\"Celebrating the regional trophy win with coaches and physical trainers.\"},{\"url\":\"\\/gallery\\/485138439_1112500837568909_1171834009923344545_n.jpg\",\"title\":\"Basketball Team Drill\",\"description\":\"Practicing defense tactics and rebounds in the indoor court arena.\"},{\"url\":\"\\/gallery\\/485145618_9581308151929606_7641301265463067437_n.jpg\",\"title\":\"State-of-the-Art Classroom\",\"description\":\"Smartboards and ergonomic seating tables enhancing learning focus.\"},{\"url\":\"\\/gallery\\/485190954_1112500570902269_8288131153090815699_n.jpg\",\"title\":\"Recreational Green Parks\",\"description\":\"Lush gardens designed for eco-sensitization and student break times.\"},{\"url\":\"\\/gallery\\/485731599_9581308111929610_8631168577359249964_n.jpg\",\"title\":\"School Entry Archway\",\"description\":\"Our aesthetic, security-monitored entrance gate welcoming students.\"},{\"url\":\"\\/gallery\\/485758830_1112500680902258_7731972126313446841_n.jpg\",\"title\":\"Teachers Learning Center\",\"description\":\"The dedicated faculty arena for training seminars and lesson planning.\"},{\"url\":\"\\/gallery\\/485980888_9590200271040394_5936883891415037732_n.jpg\",\"title\":\"Science Fair Presentation\",\"description\":\"Parents and teachers reviewing innovative engineering mock projects.\"},{\"url\":\"\\/gallery\\/485981810_9590200161040405_359722123040599458_n.jpg\",\"title\":\"Arts & Crafts Gallery Exhibition\",\"description\":\"A creative showcase of clay models, paintings, and canvas designs.\"},{\"url\":\"\\/gallery\\/486054350_1116713687147624_4086885150192183137_n.jpg\",\"title\":\"Independence Day Parade\",\"description\":\"NCC cadets presenting the guard of honor during the flag hoisting.\"},{\"url\":\"\\/gallery\\/486159018_1112500714235588_8594873119287038664_n.jpg\",\"title\":\"Math Olympiad Prep\",\"description\":\"Advanced logical reasoning and mathematics drills in our resource rooms.\"},{\"url\":\"\\/gallery\\/487089101_1121046263381033_2393694709069016100_n.jpg\",\"title\":\"Biology Lab Classification\",\"description\":\"Students researching plant tissue specimens under light microscopes.\"},{\"url\":\"\\/gallery\\/487179822_1121046096714383_5614342915506887026_n.jpg\",\"title\":\"Chemistry Volumetric Analysis\",\"description\":\"Performing chemical titration practices in our fully equipped labs.\"},{\"url\":\"\\/gallery\\/487696894_1123852146433778_1489242256585165569_n.jpg\",\"title\":\"Yoga and Meditation Session\",\"description\":\"Promoting mental clarity and inner balance during physical training hours.\"},{\"url\":\"\\/gallery\\/487698226_1123852343100425_807839357526167123_n.jpg\",\"title\":\"Table Tennis Matches\",\"description\":\"Intense inter-house table tennis tournament drills inside the gymnasium.\"},{\"url\":\"\\/gallery\\/487775176_1124345526384440_2524581491999136662_n.jpg\",\"title\":\"Skating Academy Drills\",\"description\":\"Developing coordination and high agility drills under school coaches.\"},{\"url\":\"\\/gallery\\/487821609_1124345549717771_496302793650938709_n.jpg\",\"title\":\"School Swimming Pool\",\"description\":\"Equipped with certified lifesavers and modern temperature control systems.\"},{\"url\":\"\\/gallery\\/487917216_1123852559767070_383639409212605712_n.jpg\",\"title\":\"Modern Chemistry Lab Arena\",\"description\":\"Fully exhaust-regulated workspace designed for chemistry practices.\"},{\"url\":\"\\/gallery\\/487925399_1124345523051107_3121875572283714452_n.jpg\",\"title\":\"Sports Hall Interior\",\"description\":\"Versatile synthetic indoor arena for badminton and gymnastics.\"},{\"url\":\"\\/gallery\\/488189035_1123852186433774_1583533490548750596_n.jpg\",\"title\":\"School Entrance Lobby\",\"description\":\"Beautiful receptionist desks and trophy showcases representing glory.\"},{\"url\":\"\\/gallery\\/488216031_1123852433100416_4776950320059655080_n.jpg\",\"title\":\"Annual Principal Address\",\"description\":\"The principal welcoming governors and guests during annual day.\"},{\"url\":\"\\/gallery\\/488247985_1123852106433782_5198809109826584579_n.jpg\",\"title\":\"Awarding Scholarship Checks\",\"description\":\"Incentivizing excellence by giving annual merit-based scholarships.\"},{\"url\":\"\\/gallery\\/488251761_1123852529767073_1281476236495953361_n.jpg\",\"title\":\"Teachers Day Celebrations\",\"description\":\"Creative functions prepared by senior students for their mentors.\"},{\"url\":\"\\/gallery\\/488274134_1123852483100411_8350735656058729555_n.jpg\",\"title\":\"Republic Day Celebration Parade\",\"description\":\"School band presenting musical drills for national honors.\"},{\"url\":\"\\/gallery\\/488507646_1123852286433764_1499281791975581441_n.jpg\",\"title\":\"Grand Parents Day Functions\",\"description\":\"Bridging generations with emotional acts and stage presentations.\"},{\"url\":\"\\/gallery\\/582537847_1327890756029915_3000299894603074358_n.jpg\",\"title\":\"Primary School Activity Room\",\"description\":\"Promoting tactile and sensory development with puzzles and blocks.\"},{\"url\":\"\\/gallery\\/584674251_1327890712696586_5992226931136141227_n.jpg\",\"title\":\"Robotics Workshop Training\",\"description\":\"Designing electronic micro-circuits and coding robotic gears.\"},{\"url\":\"\\/gallery\\/715323451_1507909828028006_8822091589871330205_n.jpg\",\"title\":\"Alumni Meet Gathering\",\"description\":\"Welcoming former batches of graduates back to their second home.\"},{\"url\":\"\\/gallery\\/716431819_1507909751361347_6219224248670980883_n.jpg\",\"title\":\"Inter-School Debate Finals\",\"description\":\"Empowering young orators during argumentative elocution contests.\"},{\"url\":\"\\/gallery\\/716574356_1507909694694686_8252793927191446003_n.jpg\",\"title\":\"Annual Sports Meet Inaugural Parade\",\"description\":\"Houses marching in coordination representing institutional pride.\"},{\"url\":\"\\/gallery\\/716614936_1507909638028025_6100307475238447176_n.jpg\",\"title\":\"Closing Ceremony & Torch Run\",\"description\":\"Concluding the sports meets with honors and a final torch run.\"},{\"url\":\"\\/uploads\\/image\\/1782104072_Gemini_Generated_Image_m8vxmom8vxmom8vx.png\",\"title\":\"Gemini_Generated_Image_m8vxmom8vxmom8vx\",\"description\":\"\"}]}', 'draft', '1', '2026-06-22 11:20:11');
