INSERT INTO `blocks` (`id`, `page_id`, `block_type`, `sort_order`, `data`, `status`, `version`, `is_visible`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES ('96', '2', 'text', '0', '{\"heading\":\"Welcome to The Greenwood School\",\"body\":\"<p>At Greenwood Public School, we provide a holistic and modern co-educational learning experience. Equipped with smart classrooms, advanced computer centers, a rich library, and vast playfields, we nurture creative, physical, and personal growth.<\\/p><p>Driven by our motto, <strong>\\u201cPath Maker for Path Seekers\\u201d<\\/strong>, our multidisciplinary teaching methodology empowers every student to discover their potential and prepare themselves to excel in school, university, and the dynamic global workspace.<\\/p>\",\"alignment\":\"left\"}', 'published', '1', '1', NULL, NULL, '2026-06-22 14:36:30', '2026-06-22 14:36:30');
INSERT INTO `blocks` (`id`, `page_id`, `block_type`, `sort_order`, `data`, `status`, `version`, `is_visible`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES ('97', '2', 'text', '1', '{\"heading\":\"Message From Principal - Leading the Way in Academic Brilliance\",\"body\":\"<p>\\\"At Greenwood, we believe education is not merely the acquisition of facts, but the training of the mind to think critically, innovate fearlessly, and lead with empathy. Our mission is to provide an ecosystem where students discover their true potential and prepare themselves to make lasting contributions to society.\\\"<\\/p><p>We welcome you to experience our progressive curriculum, high-tech environments, and warm community where child protection and student development are our highest priorities.<\\/p>\",\"alignment\":\"left\"}', 'published', '1', '1', NULL, NULL, '2026-06-22 14:36:30', '2026-06-22 14:36:30');
INSERT INTO `blocks` (`id`, `page_id`, `block_type`, `sort_order`, `data`, `status`, `version`, `is_visible`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES ('98', '2', 'text', '2', '{\"heading\":\"Message From Trustee - Nurturing Values & Holistic Development\",\"body\":\"<p>\\\"Value-based modern education has always been a dream. Education has to keep pace with the changing times, but should have the strong foundation based on our old value system. Keeping that fact in mind, this organization was started\\u2014to cater to the needs of persons who want to bring their children up with a difference.\\\"<\\/p><p>\\\"Sheer academic proficiency cannot determine growth, because growth cannot signify physical growth only. The object of education is to prepare the young to educate themselves throughout their lives. The Greenwood is a school that has been started with the belief and hope that everyone\'s dream of making a holistic individual is made a reality, supported by a perfect learning environment.\\\"<\\/p>\",\"alignment\":\"left\"}', 'published', '1', '1', NULL, NULL, '2026-06-22 14:36:30', '2026-06-22 14:36:30');
INSERT INTO `blocks` (`id`, `page_id`, `block_type`, `sort_order`, `data`, `status`, `version`, `is_visible`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES ('99', '2', 'cards', '3', '{\"title\":\"Vision, Mission & Key Objectives\",\"columns\":3,\"cards\":[{\"title\":\"Our Vision\",\"description\":\"To be a premier center of educational excellence that nurtures creative thinkers, ethical leaders, and global citizens. We envision a learning ecosystem where academic rigor merges with character building, empowering students to confidently navigate a dynamic world.\",\"image\":\"\",\"link\":\"\"},{\"title\":\"Our Mission\",\"description\":\"To provide a stimulating, inclusive, and technology-driven environment where students explore their unique potential. Grounded in our motto, \\u201cPath Maker for Path Seekers\\u201d, we deliver a multidisciplinary curriculum that fosters critical thinking, social responsibility, physical wellness, and a lifelong passion for learning.\",\"image\":\"\",\"link\":\"\"},{\"title\":\"Key Objectives\",\"description\":\"1. To provide opportunities through stimulating, safe and supportive environment.\\\\n2. To engage students in active, collaborative and technology based learning.\\\\n3. To enrich the lives of its pupils through encouraging participation in cultural and sporting programmes.\",\"image\":\"\",\"link\":\"\"}]}', 'published', '1', '1', NULL, NULL, '2026-06-22 14:36:30', '2026-06-22 14:36:30');
