INSERT INTO `site_settings` (`id`, `setting_key`, `setting_value`, `setting_group`, `updated_by`, `updated_at`) VALUES ('2', 'principal_message', 'At Greenwood, we believe education is not merely the acquisition of facts, but the training of the mind to think critically, innovate fearlessly, and lead with empathy. Our mission is to provide an ecosystem where students discover their true potential and prepare themselves to make lasting contributions to society.', 'principal', '1', '2026-06-22 15:01:39');
