INSERT INTO `site_settings` (`id`, `setting_key`, `setting_value`, `setting_group`, `updated_by`, `updated_at`) VALUES ('5', 'trustee_message', 'Value-based modern education has always been a dream. Education has to keep pace with the changing times, but should have the strong foundation based on our old value system. Keeping that fact in mind, this organization was started—to cater to the needs of persons who want to bring their children up with a difference.', 'trustee', '1', '2026-06-22 15:01:39');
